/**
 * Nucleus Runtime — injected automatically into custom overlays.
 * Users can reference data via data-nucleus attributes in their HTML.
 * Do NOT edit this file — changes affect all custom overlays.
 */
(function NucleusRuntime() {
  'use strict';

  var BASE = window.__NUCLEUS_BASE__;
  if (!BASE || BASE === 'null' || !BASE.startsWith('http')) {
    BASE = 'http://localhost:3000';
  }

  function setAll(sel, val) {
    document.querySelectorAll(sel).forEach(function (el) { el.textContent = val; });
  }
  function setSrc(sel, val) {
    document.querySelectorAll(sel).forEach(function (el) { el.src = val; });
  }
  function wsHost() { return BASE.replace(/^https?:\/\//, ''); }
  function wsProto() { return BASE.startsWith('https') ? 'wss' : 'ws'; }

  /* ── Music ──────────────────────────────────────────────────── */
  if (document.querySelector('[data-nucleus^="music"]')) {
    (function pollMusic() {
      fetch(BASE + '/music/current')
        .then(function (r) { return r.json(); })
        .then(function (d) {
          setAll('[data-nucleus="music-title"]', d.title || '—');
          setAll('[data-nucleus="music-artist"]', d.artist || '');
          if (d.thumbnail) setSrc('[data-nucleus="music-thumb"]', 'data:image/png;base64,' + d.thumbnail);
          document.querySelectorAll('[data-nucleus="music-wrap"]').forEach(function (el) {
            el.style.display = d.title ? '' : 'none';
          });
        })
        .catch(function () {})
        .finally(function () { setTimeout(pollMusic, 3000); });
    })();
  }

  /* ── Viewers / Stream status ────────────────────────────────── */
  if (document.querySelector('[data-nucleus^="viewers"],[data-nucleus^="stream"]')) {
    (function pollStatus() {
      fetch(BASE + '/stream/status')
        .then(function (r) { return r.json(); })
        .then(function (d) {
          setAll('[data-nucleus="viewers-twitch"]',  d.twitch_viewers  != null ? String(d.twitch_viewers)  : '');
          setAll('[data-nucleus="viewers-youtube"]', d.youtube_viewers != null ? String(d.youtube_viewers) : '');
          setAll('[data-nucleus="viewers-kick"]',    d.kick_viewers    != null ? String(d.kick_viewers)    : '');
          var tot = (d.twitch_viewers || 0) + (d.youtube_viewers || 0) + (d.kick_viewers || 0);
          setAll('[data-nucleus="viewers-total"]', String(tot));
          var live = !!(d.twitch_live || d.youtube_live || d.kick_live);
          document.querySelectorAll('[data-nucleus="stream-live"]').forEach(function (el) {
            el.style.display = live ? '' : 'none';
          });
          document.querySelectorAll('[data-nucleus="stream-offline"]').forEach(function (el) {
            el.style.display = live ? 'none' : '';
          });
        })
        .catch(function () {})
        .finally(function () { setTimeout(pollStatus, 15000); });
    })();
  }

  /* ── Chat WebSocket ─────────────────────────────────────────── */
  var chatEl = document.querySelector('[data-nucleus="chat"]');
  if (chatEl) {
    var maxMsgs  = parseInt(chatEl.getAttribute('data-max-messages') || '30', 10);
    var timeout  = parseInt(chatEl.getAttribute('data-timeout') || '30000', 10);

    function addMsg(d) {
      var row = document.createElement('div');
      row.className = 'nucleus-msg';
      row.setAttribute('data-platform', d.platform || '');
      var user = document.createElement('span');
      user.className = 'nucleus-user';
      user.style.color = d.color || '#00c8e0';
      user.textContent = d.user || '';
      var sep = document.createTextNode(': ');
      var text = document.createElement('span');
      text.className = 'nucleus-text';
      text.textContent = d.message || '';
      row.appendChild(user);
      row.appendChild(sep);
      row.appendChild(text);
      chatEl.insertBefore(row, chatEl.firstChild);
      while (chatEl.children.length > maxMsgs) chatEl.removeChild(chatEl.lastChild);
      if (timeout > 0) setTimeout(function () { if (row.parentNode) row.remove(); }, timeout);
    }

    // History
    fetch(BASE + '/chat/history')
      .then(function (r) { return r.json(); })
      .then(function (msgs) { msgs.slice(-20).forEach(addMsg); })
      .catch(function () {});

    // Live
    (function connectChat() {
      var ws = new WebSocket(wsProto() + '://' + wsHost() + '/ws/chat');
      ws.onmessage = function (e) { try { addMsg(JSON.parse(e.data)); } catch (err) {} };
      ws.onclose   = function () { setTimeout(connectChat, 3000); };
    })();
  }

  /* ── Overlay events ─────────────────────────────────────────── */
  (function connectEvents() {
    var ws = new WebSocket(wsProto() + '://' + wsHost() + '/ws/overlay-events');
    ws.onclose = function () { setTimeout(connectEvents, 3000); };
  })();

})();
